class Solution:
    def canVisitAllRooms(self, rooms: List[List[int]]) -> bool:
        visited = [False] * len(rooms)
        visited[0] = True
        queue = [0]
        while queue:
            room = queue.pop(0)
            for key in rooms[room]:
                if not visited[key]:
                    visited[key] = True
                    queue.append(key)
        return all(visited)
```
